import{_ as e,o as a,c as t,j as r,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"快枪手","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/2.D级/快枪手.md","filePath":"4.资源分区/7.物品与装备/7.载具及随从/随从/2.D级/快枪手.md"}'),s={name:"4.资源分区/7.物品与装备/7.载具及随从/随从/2.D级/快枪手.md"};function o(d,b,l,_,i,c){return a(),t("div",null,[...b[0]||(b[0]=[r("h1",{id:"快枪手",tabindex:"-1"},[p("快枪手 "),r("a",{class:"header-anchor",href:"#快枪手","aria-label":'Permalink to "快枪手"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风022")])])],-1),n('<h1 id="快枪手-1" tabindex="-1">快枪手 <a class="header-anchor" href="#快枪手-1" aria-label="Permalink to &quot;快枪手&quot;">​</a></h1><p>快枪手<br> D+500<br> 这是一只戴着皮手套的手，一只在外形上和普通人类的手毫无区别的手。<br> 但它是真正的快枪手！射击，骑乘，劫掠，样样精通！<br> ▓▓▓▓基本能力值<br> ▓智力 2<br> ▓感知 4<br> ▓决心 4</p><p>▓力量 4<br> ▓敏捷 6<br> ▓耐力 4</p><p>▓风度 2<br> ▓操控 2<br> ▓沉着 6</p><p>▓▓▓▓技能<br> ▓知识3<br> ▓器用3 轻型载具3<br> ▓手艺3<br> ▓专注3 意志3</p><p>▓运动5 反射5 投掷3<br> ▓生存3 强韧3<br> ▓射击5 手枪5<br> ▓武技1</p><p>▓洞察3 侦查3<br> ▓隐秘1<br> ▓表达1<br> ▓社交1</p><p>▓▓▓▓衍生属性值<br> ▓体积 1<br> ▓速度 14<br> ▓先攻 r2d10+12<br> ▓防御 5+1<br> ▓生命值 8<br> ▓意志力池 10<br> ▓意志 10+1<br> ▓反射 16+3<br> ▓强韧 10+1<br> ▓侦查 10+1<br> ▓敏感范围 80米<br> ▓▓▓▓攻击预设：<br> 手枪射击：敏捷6+射击5+手枪5+武器伤害3L=19+2<br> 高速5 射程20米<br> ▓▓▓▓防御预设：<br> 基础防御3+1<br> 骑乘轻型生物载具：<br> 基础防御4+闪避防御2=6+1<br> 免疫C级措手不及<br> ▓▓▓▓特性：<br> 一把好枪：<br> 枪是快枪手的生命。失去枪的快枪手，已经变成食物了。<br> 快枪手拥有一把无限子弹的左轮手枪，数据等同现实小型左轮手枪。</p><p>骑乘好手：<br> 马是快枪手生命中不可缺少的一环。失去马的快枪手，已经变成化肥了。<br> 在骑乘轻型生物载具时，快枪手获得2点闪避防御，并且免疫C级措手不及。</p><p>真正的快枪手：<br> 更快的拔枪，瞄准，射击，才能让你从对决中活下来。<br> 快枪手只需要一个自由动作，便可以拔出自己的手枪。<br> 快枪手在使用手枪射击时，视为已经瞄准了两轮。</p><p>真正的快枪“手”<br> 尽管对于快枪手来说这有些难以启齿，但是快枪手确实可以当作人类的手来使用。<br> 你可以切下自己的手，用快枪手来代替。快枪手会代替你射击。在使用手枪射击时，你获得【预设】特性，正常通过防御。<br> 切下手时需要承受2点不可避免的恶性伤害，除非你已经失去了这只手。分离快枪手时，快枪手和你都需要承受2点不可避免的恶性伤害。</p><hr><p>Copyright ? 2024 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',13)])])}const m=e(s,[["render",o]]);export{f as __pageData,m as default};
